const startedAt=new Date().toISOString();
const missingVars=[];
if(!$env.TELEGRAM_BOT_TOKEN)missingVars.push("TELEGRAM_BOT_TOKEN");
if(!$env.TELEGRAM_CHAT_ID)missingVars.push("TELEGRAM_CHAT_ID");
if(!$env.DB_CONNECTION_STRING&&!$env.POSTGRES_HOST)missingVars.push("DB_CONNECTION_STRING or POSTGRES_HOST");
if(missingVars.length>0)throw new Error("Pre-hook FAIL: "+missingVars.join(", "));
const out={startedAt,contextOk:true,workflow:"linkedin-campaign-analyzer"};
return[{json:out}];

const ctx=$("Pre-Hook: Valida Contesto").first().json;
const rows=$input.all().map(item=>item.json);
const endedAt=new Date().toISOString();
const durationMs=new Date(endedAt)-new Date(ctx.startedAt);
const alerts=[];
const campaignLines=[];
rows.forEach(row=>{
  const sent=parseInt(row.invite_sent)||0;
  const accepted=parseInt(row.invite_accepted)||0;
  const messaged=parseInt(row.messaged)||0;
  const replied=parseInt(row.replied)||0;
  const pending=parseInt(row.pending_count)||0;
  const total=parseInt(row.total_leads)||0;
  const campaign=row.campaign_id||"default";
  const acceptanceRate=sent>0?((accepted/sent)*100).toFixed(1):"n/d";
  const replyRate=messaged>0?((replied/messaged)*100).toFixed(1):"n/d";
  const pendingRatio=total>0?((pending/total)*100).toFixed(1):"n/d";
  campaignLines.push("
*Campagna: "+campaign+"*");
  campaignLines.push("  Inviti: "+sent+" → accettati "+accepted+" ("+acceptanceRate+"%)");
  campaignLines.push("  Messaggi: "+messaged+" → risposte "+replied+" ("+replyRate+"%)");
  campaignLines.push("  Pending: "+pending+" ("+pendingRatio+"%)");
  const pNum=parseFloat(pendingRatio);
  const aNum=parseFloat(acceptanceRate);
  if(!isNaN(pNum)&&pNum>30)alerts.push("⚠️ Campagna "+campaign+": pending "+pendingRatio+"% > 30% → RISCHIO ACCOUNT");
  if(!isNaN(aNum)&&aNum<20)alerts.push("🔍 Campagna "+campaign+": acceptance "+acceptanceRate+"% < 20% → review targeting");
});
const now=new Date();
const dateStr=now.toLocaleDateString("it-IT",{day:"2-digit",month:"2-digit",year:"numeric"});
const lines=["📊 *Campaign Analyzer — "+dateStr+"*"];
if(rows.length===0){lines.push("
Nessuna campagna con dati negli ultimi 30 giorni.");}else{lines.push("
*Campagne analizzate: "+rows.length+"*");campaignLines.forEach(l=>lines.push(l));}
if(alerts.length>0){lines.push("
*ALERT:*");alerts.forEach(a=>lines.push("  "+a));}
lines.push("
_Durata: "+durationMs+"ms_");
const out={report:lines.join("
"),alertCount:alerts.length,campaigns:rows.length,startedAt:ctx.startedAt,endedAt,durationMs};
return[{json:out}];

const current = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const lastAlerts = staticData.lastAlerts || [];
const lastRunDate = staticData.lastRunDate || null;
const currentAlerts = current.report.match(/[⚠️🔍][^\n]*/g) || [];
const alertsChanged = JSON.stringify(currentAlerts.sort()) !== JSON.stringify(lastAlerts.sort());
const isFirstRun = !lastRunDate;
// Aggiorna lo stato persistente
staticData.lastAlerts = currentAlerts;
staticData.lastRunDate = new Date().toISOString();
const shouldSend = isFirstRun || alertsChanged || current.alertCount > 0;
return [{ json: { ...current, shouldSend, alertsChanged, isFirstRun } }];

const r=$input.first().json;
const log={workflow:"linkedin-campaign-analyzer",campaigns:r.campaigns,alertCount:r.alertCount,durationMs:r.durationMs,loggedAt:new Date().toISOString()};
console.log("[POST-HOOK campaign-analyzer]",JSON.stringify(log));
return[{json:log}];
